5	/**
6	 * Read and parse a JSON file.
7	 */
8	export async function readJSON<T>(filePath: string): Promise<T> {
9	  const contents = await readFile(filePath, "utf-8");
10	  return JSON.parse(contents) as T;
11	}
12	
13	/**
14	 * Write JSON to a file atomically using write-to-temp-then-rename.
15	 * Creates parent directories if they don't exist.
16	 */
17	export async function atomicWriteJSON(filePath: string, data: unknown): Promise<void> {
18	  const dir = dirname(filePath);
19	  if (!existsSync(dir)) {
20	    mkdirSync(dir, { recursive: true });
21	  }
22	
23	  const tmpPath = join(dir, `.tmp-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
24	  try {
25	    await writeFile(tmpPath, JSON.stringify(data, null, 2) + "\n", "utf-8");
26	    await rename(tmpPath, filePath);
27	  } catch (err) {
28	    // Clean up temp file if rename fails
29	    try {
30	      const { unlinkSync } = await import("node:fs");
31	      unlinkSync(tmpPath);
32	    } catch {
33	      // Ignore cleanup errors
34	    }
35	    throw err;
36	  }
37	}
