5	/**
6	 * Handler for the `trackgentic init` command.
7	 * Creates a `.trackgentic/` directory in the current working directory.
8	 */
9	export async function initAction(): Promise<void> {
10	  try {
11	    const tracker = new Tracker();
12	    const result = await tracker.init();
13	    writeStdout(result);
14	    process.exit(0);
15	  } catch (err) {
16	    if (err instanceof TrackgenticError) {
17	      writeStderr({ result: err.result, message: err.message });
18	      process.exit(err.exitCode);
19	    }
20	    // Unexpected errors
21	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
22	    process.exit(1);
23	  }
