import { mkdtempSync, rmSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";

/**
 * Create a temporary directory for test isolation.
 * Each test gets its own unique directory under the system temp dir.
 */
export function createTestDir(prefix = "trackgentic-test"): string {
  return mkdtempSync(join(tmpdir(), `${prefix}-`));
}

/**
 * Clean up a temporary test directory.
 * Safe to call even if the directory doesn't exist.
 */
export function cleanupTestDir(dir: string): void {
  rmSync(dir, { recursive: true, force: true });
}

import type { CreateParams, UpdateParams } from "../../src/types/api";

/**
 * Factory function for creating test CreateParams.
 * Provides sensible defaults that can be overridden.
 */
export function createIssueParams(overrides?: Partial<CreateParams>): CreateParams {
  return {
    title: "Test issue",
    priority: 2,
    ...overrides,
  };
}

/**
 * Factory function for creating test UpdateParams.
 * Provides sensible defaults that can be overridden.
 */
export function updateIssueParams(overrides?: Partial<UpdateParams>): UpdateParams {
  return {
    status: "in-progress",
    ...overrides,
  };
}

import { expect } from "bun:test";
import type { TrackgenticError } from "../../src/core/errors";

/**
 * Assert that a result is a TrackgenticError with the expected result code.
 */
export function expectError(result: unknown, expectedCode: string): void {
  expect(result).toBeDefined();
  const err = result as TrackgenticError;
  expect(err.result).toBe(expectedCode);
}

/**
 * Assert that a result is a success (has result: "OK").
 */
export function expectOk(result: { result: string }): void {
  expect(result.result).toBe("OK");
}

